/// <summary>
/// Scoped service (per circuit) that tracks low-stock alert counts and
/// notifies all subscribed components when data changes.
/// </summary>
public class InventoryAlertService
{
    private static readonly Random _random = new();

    public int CurrentLowStockCount { get; private set; }

    /// <summary>
    /// Fired whenever <see cref="CurrentLowStockCount"/> is updated.
    /// Components must subscribe via InvokeAsync(StateHasChanged) to
    /// safely re-render from the background polling thread.
    /// </summary>
    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        int count;
        lock (_random)
        {
            count = _random.Next(0, 16);
        }
        return Task.FromResult(count);
    }

    /// <summary>
    /// Updates the cached count and notifies all subscribers.
    /// Called by whichever component owns the polling loop.
    /// </summary>
    public void UpdateCount(int newCount)
    {
        CurrentLowStockCount = newCount;
        OnChange?.Invoke();
    }
}

