@* Interactive island inside the static layout — handles change events. *@
@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_1a9c86ee9c7f4d70b3ffe2ac6c29b6bf.Services

<select class="form-select form-select-sm w-auto"
        value="@_selectedId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private string _selectedId = "WH-A";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "WH-A";
        var name = WarehouseInfo.AvailableWarehouses
            .First(w => w.Id == _selectedId).Name;

        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo { WarehouseId = _selectedId, WarehouseName = name });
    }
}

