@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@implements IDisposable
@using sv_1a9c86ee9c7f4d70b3ffe2ac6c29b6bf.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@_warehouse?.WarehouseName</p>
                <p class="text-muted">ID: @_warehouse?.WarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-1">
                    @if (AlertService.CurrentLowStockCount > 0)
                    {
                        <span class="text-danger">@AlertService.CurrentLowStockCount</span>
                    }
                    else
                    {
                        <span class="text-success">0</span>
                    }
                </p>
                <p class="text-muted">
                    @if (_polling)
                    {
                        <span>🟢 Polling every 10 s</span>
                    }
                    else
                    {
                        <span>⏸ Paused</span>
                    }
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Last Checked</h5>
                <p class="card-text fs-4">@_lastChecked?.ToString("HH:mm:ss")</p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? _warehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private bool _polling;
    private DateTime? _lastChecked;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Subscribe to alert changes so we re-render when polling updates the count.
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _alertHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed — restart polling with new warehouse immediately.
        if (_polling && _warehouse is not null)
        {
            StopPolling();
            await PollOnceAsync();
            await StartPollingAsync();
        }
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _polling = true;

        // Do an initial poll right away.
        await PollOnceAsync();

        // Fire-and-forget the loop; it will cancel via the token on Dispose.
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollOnceAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse change.
        }
    }

    private async Task PollOnceAsync()
    {
        if (_warehouse is null) return;
        var count = await AlertService.GetLowStockCountAsync(_warehouse.WarehouseId);
        _lastChecked = DateTime.Now;

        // This notifies ALL subscribers (sidebar badge, this page, etc.)
        AlertService.UpdateCount(count);
    }

    private void StopPolling()
    {
        _polling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _alertHandler;
        StopPolling();
    }
}

